sql:
SELECT AVG(CAST(on_sale_price AS REAL)) AS average_current_sale_price
FROM nfts
WHERE is_auction = 0;

external_knowledge:
- 'Auction stars' refers to NFTs that are currently being auctioned.;
- 'Basking in the spotlight' indicates NFTs that are drawing attention, which in this context, means they are on sale and being auctioned.;
- 'Highest bid they've attracted' refers to the maximum sale price achieved for each NFT during its auction.

sql:
SELECT nft_id, name, rarity
FROM nfts
WHERE rarity = 'uncommon';

SELECT AVG(nfts.royalty_percentage) AS 'Average Royalty Percentage'
FROM nfts
WHERE nfts.rarity = 'Common';

SELECT n.name
FROM nfts n
INNER JOIN sales s ON n.nft_id = s.nft_id;

SELECT creator_id, COUNT(nft_id) AS total_nfts
FROM nfts
GROUP BY creator_id;

SELECT name
FROM nfts
WHERE reserve_price = (SELECT MAX(reserve_price) FROM nfts);

external_knowledge:
- "cast their nets into the auction waters" refers to NFTs that were put up for auction;
- "caught by the tides of time" means that the auction has ended (the end date is in the past);
- "identities" and "aliases" refer to the names of the NFTs and usernames of the buyers or sellers.

sql:
SELECT name, on_sale_price, rarity, supply_circulating 
FROM nfts 
WHERE nft_id = 0;

SELECT AVG(s.sale_price) AS average_price
FROM sales AS s
WHERE s.sale_price > 10000;

SELECT username
FROM users
WHERE user_id NOT IN (SELECT buyer_id FROM sales);

SELECT nft_id
FROM nft_attributes
WHERE boosts2 != 0;

SELECT DISTINCT creator_id
FROM nfts
WHERE on_sale_price IS NOT NULL AND royalty_percentage > (SELECT AVG(royalty_percentage) FROM nfts);

SELECT username 
FROM users 
WHERE user_id = (
  SELECT buyer_id 
  FROM sales 
  WHERE sale_price = (
    SELECT MIN(sale_price) 
    FROM sales
  )
);
